const Spost = ({ image, channelLogo, title, channelName, views, time }) => {
    return (
        <div className="search-post">
            <div >
                <img className="search-image" src={image} />
            </div>
            <div className="search-post-details">
                <div className="text-details">
                    <h3 className="title">{title}</h3>
                    <span>{views}</span> . <span>{time}</span>
                    <br />
                    <div className="channel-info">
                        <img src={channelLogo} className="channel-logo-search" />
                        <span>{channelName}</span>
                    </div>
                    <span>Description dlkfsldfn .ksdnk.kdnf</span>
                </div>
            </div>
        </div>
    )
}

export default Spost
