const Post = ({ image, channelLogo, title, channelName, views, time }) => {
    return (
        <div className="post">
            <div >
                <img className="post-image" src={image} alt="" />
            </div>
            <div className="details">
                <div>
                    <img src={channelLogo} alt="" className="channel-logo" />
                </div>
                <div className="text-details">
                    <h3 className="title">{title}</h3>
                    <p>{channelName}</p>
                    <span>{views}</span> . <span>{time}</span>

                </div>
            </div>
        </div>
    )
}

export default Post
